import{_ as e,o as t,c as r,a2 as n}from"./chunks/framework.ZhLefgN8.js";const f=JSON.parse('{"title":"基金收费规则","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"funds-and-wealth/funds/fund-fees.md","filePath":"zh-CN/funds-and-wealth/funds/fund-fees.md"}'),o={name:"funds-and-wealth/funds/fund-fees.md"};function s(d,a,l,h,i,u){return t(),r("div",null,[...a[0]||(a[0]=[n('<h1 id="基金收费规则" tabindex="-1">基金收费规则 <a class="header-anchor" href="#基金收费规则" aria-label="Permalink to &quot;基金收费规则&quot;">​</a></h1><p>长桥平台基金申购赎回费率为零，管理费和托管费由基金公司收取并在净值中扣除。</p><h2 id="费用总览" tabindex="-1">费用总览 <a class="header-anchor" href="#费用总览" aria-label="Permalink to &quot;费用总览&quot;">​</a></h2><p>申购费率：0%（长桥平台收取）；赎回费率：0%（长桥平台收取）；管理费和托管费由基金公司收取，不同基金费率不同。</p><h2 id="申购费-认购费" tabindex="-1">申购费（认购费） <a class="header-anchor" href="#申购费-认购费" aria-label="Permalink to &quot;申购费（认购费）&quot;">​</a></h2><p>长桥平台收取的申购费率为 0%，即免申购费。</p><p>在长桥平台购买基金，申购费率为 <strong>0%</strong>，投资者无需支付申购费用。</p><h2 id="赎回费" tabindex="-1">赎回费 <a class="header-anchor" href="#赎回费" aria-label="Permalink to &quot;赎回费&quot;">​</a></h2><p>长桥平台收取的赎回费率为 0%，即免赎回费。</p><p>在长桥平台卖出（赎回）基金，赎回费率为 <strong>0%</strong>，投资者无需支付赎回费用。</p><h2 id="管理费" tabindex="-1">管理费 <a class="header-anchor" href="#管理费" aria-label="Permalink to &quot;管理费&quot;">​</a></h2><p>管理费由<strong>基金公司</strong>收取，用于支付基金的日常运营和管理成本。不同基金的管理费率不同，具体费率请查看对应基金的详情页。</p><p>管理费已在基金每日净值中自动扣除，投资者无需单独支付。</p><h2 id="托管费" tabindex="-1">托管费 <a class="header-anchor" href="#托管费" aria-label="Permalink to &quot;托管费&quot;">​</a></h2><p>托管费由<strong>基金公司</strong>收取，用于支付基金资产的托管成本。不同基金的托管费率不同，具体费率请查看对应基金的详情页。</p><p>托管费同样已在基金每日净值中自动扣除，投资者无需单独支付。</p><h2 id="费用扣除说明" tabindex="-1">费用扣除说明 <a class="header-anchor" href="#费用扣除说明" aria-label="Permalink to &quot;费用扣除说明&quot;">​</a></h2><p>管理费和托管费均在基金<strong>每日净值</strong>中自动扣除，投资者看到的单位净值已是扣除上述费用后的净值，无需额外支付任何费用。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/funds-and-wealth/基金买入与卖出规则">基金买入与卖出规则</a> — 交易规则与时间限制</li></ul>',20)])])}const c=e(o,[["render",s]]);export{f as __pageData,c as default};
